module RefModule(
    input [1:0] in,
    output out0, out1, out2, out3
    );reg [3:0] obf_out;

assign out0 = obf_out[0];
assign out1 = obf_out[1];
assign out2 = obf_out[2];
assign out3 = obf_out[3];

always @ (*)
    case (in)
    2'b00: obf_out = 4'b0001;
    2'b01: obf_out = 4'b0010;
    2'b10: obf_out = 4'b0100;
    2'b11: obf_out = 4'b1000;
    endcase

endmodule
